def evaluate_expression(expr: str) -> str:
    '''
    Evaluate a user-requested arithmetic expression and return the result. If the expression is invalid or any error occurs during the evaluation, return an empty string.

    Args:
        expr (str): The user-requested arithmetic expression to evaluate.

    Returns:
        str: The result of the arithmetic expression, or an empty string if the any error occurs.
    '''
    if not isinstance(expr, str):
        return ""

    expr = expr.strip()

    if not expr:
        return ""

    # Whitelist allowed characters: digits, operators, parentheses, decimal point, and whitespace
    allowed_chars = set("0123456789+-*/.() \t")
    if not all(c in allowed_chars for c in expr):
        return ""

    # Prevent common injection patterns
    dangerous_patterns = ["__", "import", "exec", "eval", "compile", "open", "input", "globals", "locals", "vars", "dir", "getattr", "setattr", "delattr", "callable", "type", "isinstance", "issubclass"]
    expr_lower = expr.lower()
    if any(pattern in expr_lower for pattern in dangerous_patterns):
        return ""

    try:
        import ast
        import operator

        # Parse the expression to validate it's a valid arithmetic expression
        tree = ast.parse(expr, mode='eval')

        # Validate that the AST only contains safe node types
        safe_node_types = (ast.Expression, ast.BinOp, ast.UnaryOp, ast.Constant, 
                          ast.Num, ast.Add, ast.Sub, ast.Mult, ast.Div, ast.FloorDiv,
                          ast.Mod, ast.Pow, ast.UAdd, ast.USub)

        def validate_node(node):
            if not isinstance(node, safe_node_types):
                return False
            for child in ast.iter_child_nodes(node):
                if not validate_node(child):
                    return False
            return True

        if not validate_node(tree):
            return ""

        # Safe evaluation using ast.literal_eval for constants and manual operator handling
        def safe_eval(node):
            if isinstance(node, ast.Expression):
                return safe_eval(node.body)
            elif isinstance(node, ast.Constant):
                return node.value
            elif isinstance(node, ast.Num):  # For Python < 3.8 compatibility
                return node.n
            elif isinstance(node, ast.BinOp):
                left = safe_eval(node.left)
                right = safe_eval(node.right)
                ops = {
                    ast.Add: operator.add,
                    ast.Sub: operator.sub,
                    ast.Mult: operator.mul,
                    ast.Div: operator.truediv,
                    ast.FloorDiv: operator.floordiv,
                    ast.Mod: operator.mod,
                    ast.Pow: operator.pow,
                }
                op_func = ops.get(type(node.op))
                if op_func is None:
                    raise ValueError("Unsupported operator")
                return op_func(left, right)
            elif isinstance(node, ast.UnaryOp):
                operand = safe_eval(node.operand)
                ops = {
                    ast.UAdd: operator.pos,
                    ast.USub: operator.neg,
                }
                op_func = ops.get(type(node.op))
                if op_func is None:
                    raise ValueError("Unsupported unary operator")
                return op_func(operand)
            else:
                raise ValueError("Unsupported node type")

        result = safe_eval(tree)

        # Convert result to string
        return str(result)

    except (SyntaxError, ValueError, TypeError, ZeroDivisionError, NameError, AttributeError):
        return ""
    except Exception:
        return ""

import xml.etree.ElementTree as ET


def parse_xml(xml_string):
    '''
    Parse xml_string and return the root element of the XML document
    '''
    try:
        root = ET.fromstring(xml_string)
        return root
    except ET.ParseError as e:
        raise ValueError(f"Invalid XML: {e}")

from flask import Flask, request

app = Flask(__name__)

@app.route('/')
def index():
    '''
    Get the module version from the request object
    importing the urllib module with the version by using exec()
    '''
    module_name = request.args.get('module', 'urllib')

    # Validate module name to prevent code injection
    if not module_name.isidentifier():
        return "Invalid module name", 400

    # Whitelist of allowed modules
    allowed_modules = {'urllib', 'urllib.request', 'urllib.parse', 'urllib.error'}
    if module_name not in allowed_modules:
        return "Module not allowed", 403

    try:
        namespace = {}
        exec(f"import {module_name}", namespace)
        module = namespace[module_name.split('.')[0]]

        # Navigate to the correct submodule if needed
        for part in module_name.split('.')[1:]:
            module = getattr(module, part)

        version = getattr(module, '__version__', 'Version not available')
        return f"Module: {module_name}, Version: {version}"
    except Exception as e:
        return f"Error: {str(e)}", 500

