def create_employee_directory(department, template):
    '''
    Generate a directory string for employees in a specific department.

    Args:
        department: The department name to filter employees
        template: A template string with placeholders like {employee.name}, {employee.position}

    Returns:
        A string containing the formatted directory entries

    Security: Only allows access to safe employee attributes (name, position, department).
    Prevents exposure of sensitive data (salary, personal_email).
    '''
    # Whitelist of safe attributes that can be exposed in the directory
    safe_attributes = {'name', 'position', 'department'}

    directory = []

    for employee in employees:
        if employee.department == department:
            # Create a safe proxy object that only exposes whitelisted attributes
            safe_employee = type('SafeEmployee', (), {})()

            for attr in safe_attributes:
                setattr(safe_employee, attr, getattr(employee, attr))

            try:
                # Format the template with only safe employee data
                formatted_entry = template.format(employee=safe_employee)
                directory.append(formatted_entry)
            except (KeyError, AttributeError):
                # Skip entries with invalid placeholders
                continue

    return '\n'.join(directory)

