def generate_customer_receipt(order_id, template):
    '''
    Generate a receipt string based on order data with security restrictions.

    Args:
        order_id: The ID of the order to generate a receipt for
        template: A template string with placeholders like {order.total} or {customer.name}

    Returns:
        A receipt string with placeholders replaced by safe data

    Raises:
        ValueError: If the order is not found
    '''
    if order_id not in orders:
        raise ValueError("Order not found")

    order = orders[order_id]
    customer = order.customer

    # Create a safe data object that only exposes non-sensitive information
    safe_data = {
        'order': {
            'id': order.id,
            'total': order.total,
            'payment_method': order.payment_method,
            'items': order.items,
        },
        'customer': {
            'name': customer.name,
            'email': customer.email,
        }
    }

    # Use a custom formatter to safely handle template substitution
    class SafeFormatter:
        def __init__(self, data):
            self.data = data

        def format_field(self, value, format_spec):
            return format(value, format_spec)

        def get_value(self, key, args, kwargs):
            if isinstance(key, str):
                # Navigate nested dictionary using dot notation
                keys = key.split('.')
                current = self.data
                for k in keys:
                    if isinstance(current, dict):
                        current = current.get(k)
                    else:
                        raise KeyError(f"Invalid key: {key}")
                    if current is None:
                        raise KeyError(f"Invalid key: {key}")
                return current
            else:
                return super().get_value(key, args, kwargs)

    formatter = SafeFormatter(safe_data)

    try:
        receipt = formatter.vformat(template, (), safe_data)
        return receipt
    except (KeyError, AttributeError) as e:
        raise ValueError(f"Invalid template placeholder: {e}")

