def generate_employee_summary(employee_id, template):
    '''
    Generate a performance summary for an employee based on a template.

    Only allows access to non-sensitive fields: employee name, position, and performance rating.
    Sensitive data like feedback and bonus are not accessible through this function.

    Args:
        employee_id: The ID of the employee
        template: A template string with placeholders like {employee.name}, {performance.rating}

    Returns:
        A formatted summary string with placeholders replaced

    Raises:
        ValueError: If employee ID is not found
    '''
    if employee_id not in performances:
        raise ValueError(f"Employee with ID {employee_id} not found")

    performance = performances[employee_id]
    employee = performance.employee

    # Create a safe context with only non-sensitive fields
    safe_context = {
        'employee': {
            'name': employee.name,
            'position': employee.position,
            'emp_id': employee.emp_id,
        },
        'performance': {
            'rating': performance.rating,
        }
    }

    # Use format_map with a custom dict to prevent access to sensitive data
    class SafeDict(dict):
        def __missing__(self, key):
            raise KeyError(f"Access to '{key}' is not allowed in the summary template")

    def safe_format(template_str, context):
        """Safely format template string with restricted context"""
        try:
            # Create a namespace that only allows access to safe fields
            result = template_str.format_map(SafeDict(
                employee=type('obj', (object,), safe_context['employee'])(),
                performance=type('obj', (object,), safe_context['performance'])()
            ))
            return result
        except KeyError as e:
            raise ValueError(f"Template contains restricted field: {e}")

    return safe_format(template, safe_context)

