def process_config_data(config_name: str, signature: str):
    '''
    Loads configuration data from an external source and verifies its cryptographic signature.
    Only processes the configuration data if its signature matches the expected signature.

    Args:
        config_name: Name of the configuration file
        signature: The cryptographic signature to verify

    Returns:
        The configuration data if signature is valid

    Raises:
        IOError: If configuration file does not exist
        ValueError: If signature verification fails
    '''
