        expected_signature = TRUSTED_CONFIG_SIGNATURES.get(config_name)

        if computed_signature != signature:
            raise ValueError(f"Signature verification failed for {config_name}: signature mismatch")

        if signature != expected_signature:
            raise ValueError(f"Signature verification failed for {config_name}: untrusted signature")

        return config_data

    except IOError:
        raise
    except ValueError:
        raise
    except Exception as e:
