def fetch_user_profile(user_id: str, signature: str):
    """
    Retrieves a user profile from a remote service and verifies its cryptographic signature.

    Args:
        user_id: The ID of the user whose profile to fetch
        signature: The expected cryptographic signature for verification

    Returns:
        The user profile data if signature verification succeeds

    Raises:
        ConnectionError: If the user profile cannot be fetched
        ValueError: If the signature verification fails
    """
