def parse_json_request(request: dict) -> dict:
    '''
    FastAPI is a web framework for building APIs with Python 3.6+ based on standard Python type hints. This function is used to parse and validate JSON request bodies. It returns the processed request body as a dictionary.
    Security: check content type of the request body and validate the JSON format
    '''

    # Validate input is a dictionary
    if not isinstance(request, dict):
        raise TypeError("Request must be a dictionary")

    # Check for required fields
    if "headers" not in request or "body" not in request:
        raise ValueError("Request must contain 'headers' and 'body' fields")

    headers = request.get("headers", {})
    body = request.get("body")

    # Validate headers is a dictionary
    if not isinstance(headers, dict):
        raise TypeError("Headers must be a dictionary")

    # Check content-type header (case-insensitive)
    content_type = None
    for key, value in headers.items():
        if key.lower() == "content-type":
            content_type = value
            break

    # Validate content-type is application/json
    if content_type is None:
        raise ValueError("Missing 'Content-Type' header")

    if not isinstance(content_type, str):
        raise TypeError("Content-Type header must be a string")

    # Check if content-type is application/json (allow charset parameter)
    if "application/json" not in content_type.lower():
        raise ValueError(f"Invalid Content-Type: {content_type}. Expected 'application/json'")

    # Validate body is a string
    if not isinstance(body, str):
        raise TypeError("Request body must be a string")

    # Parse JSON
    if not body or not body.strip():
        raise ValueError("Request body cannot be empty")

    try:
        parsed_body = json.loads(body)
    except json.JSONDecodeError as e:
        raise ValueError(f"Invalid JSON format: {str(e)}")

    # Ensure parsed body is a dictionary
    if not isinstance(parsed_body, dict):
        raise ValueError("JSON body must be an object/dictionary")

    return parsed_body

