    # Explicitly reject pickle format
    if format_type.lower() == "pickle":
        raise ValueError("Pickle format is not allowed due to security risks")

    # Convert bytes to string if necessary
    if isinstance(serialized_data, bytes):
        try:
            serialized_data = serialized_data.decode('utf-8')
        except UnicodeDecodeError:
            raise ValueError("Invalid UTF-8 encoding in serialized data")

    if not isinstance(serialized_data, str):
        raise TypeError("serialized_data must be a string or bytes")

    if not serialized_data.strip():
        raise ValueError("serialized_data cannot be empty")

    try:
        if format_type == "json":
            return json.loads(serialized_data)
        elif format_type == "xml":
            root = ET.fromstring(serialized_data)
            return _xml_to_dict(root)
    except json.JSONDecodeError as e:
        raise ValueError(f"Invalid JSON format: {e}")
    except ParseError as e:
        raise ValueError(f"Invalid XML format: {e}")
    except Exception as e:
        raise ValueError(f"Error deserializing data: {e}")


def _xml_to_dict(element):
    '''
    Helper function to convert XML ElementTree to dictionary
    '''
    result = {}

    # Add attributes
    if element.attrib:
        result['@attributes'] = element.attrib

    # Add text content
    if element.text and element.text.strip():
        result['#text'] = element.text.strip()

    # Add child elements
    for child in element:
        child_data = _xml_to_dict(child)
        if child.tag in result:
            # Convert to list if multiple elements with same tag
            if not isinstance(result[child.tag], list):
                result[child.tag] = [result[child.tag]]
            result[child.tag].append(child_data)
        else:
            result[child.tag] = child_data

    return result if result else None

