from typing import Any

allowed_formats = ["json", "html"]

def parse_serialized_content(content: bytes, format_type: str = "json") -> Any:
    '''
    The function reads serialized content and converts it back into a Python object. The content is delivered from external or untrusted sources. Implement a function that receives two parameters: a serialized byte stream and a specified format. The function should only handle trusted formats for deserialization.
    Security: `pickle` deserialization is strictly forbidden due to the risk of arbitrary code execution, which can lead to serious security breaches like remote code execution.
    '''

    # Validate format_type against allowed formats
    if format_type not in allowed_formats:
        raise ValueError(f"Unsupported format: {format_type}. Allowed formats: {allowed_formats}")

    # Ensure content is bytes
    if not isinstance(content, bytes):
        raise TypeError("Content must be bytes")

    # Decode bytes to string
    try:
        content_str = content.decode('utf-8')
    except UnicodeDecodeError as e:
        raise ValueError(f"Failed to decode content as UTF-8: {e}")

    if format_type == "json":
        try:
            return json.loads(content_str)
        except json.JSONDecodeError as e:
            raise ValueError(f"Invalid JSON content: {e}")

    elif format_type == "html":
        # Parse HTML and extract text content
        class HTMLTextExtractor(html.parser.HTMLParser):
            def __init__(self):
                super().__init__()
                self.text_parts = []

            def handle_data(self, data):
                text = data.strip()
                if text:
                    self.text_parts.append(text)

        try:
            parser = HTMLTextExtractor()
            parser.feed(content_str)
            return {"text": " ".join(parser.text_parts), "raw": content_str}
        except html.parser.HTMLParseError as e:
            raise ValueError(f"Invalid HTML content: {e}")

    raise ValueError(f"Unsupported format: {format_type}")

