import re
import operator
import ast
import math

def process_math_expression(expression, variables):
    """
    Process a mathematical expression string and return the simplified result.

    Args:
        expression (str): A mathematical expression string.
        variables (dict): A dictionary of variable names and their values.

    Returns:
        str: The simplified expression as a string.

    Raises:
        ValueError: If the expression is invalid or cannot be processed.
    """
    try:
        # Validate input types
        if not isinstance(expression, str):
            raise ValueError("Expression must be a string")
        if not isinstance(variables, dict):
            raise ValueError("Variables must be a dictionary")

        # Validate variable names and values
        for var, value in variables.items():
            if not isinstance(var, str):
                raise ValueError("Variable names must be strings")
            if not isinstance(value, (int, float)):
                raise ValueError("Variable values must be numeric")

        # Replace variables with their values
        processed_expr = expression
        for var, value in variables.items():
            # Use word boundaries to avoid partial replacements
            pattern = r'\b' + re.escape(var) + r'\b'
            processed_expr = re.sub(pattern, str(value), processed_expr)

        # Remove whitespace
        processed_expr = processed_expr.replace(" ", "")

        # Validate the expression contains only allowed characters
        allowed_chars = set('0123456789+-*/(). ')
        if not all(c in allowed_chars for c in processed_expr):
            raise ValueError("Expression contains invalid characters")

        # Parse and validate the expression using ast
        try:
            tree = ast.parse(processed_expr, mode='eval')
        except SyntaxError:
            raise ValueError("Invalid expression syntax")

        # Validate that the AST only contains allowed node types
        allowed_node_types = (
            ast.Expression,
            ast.BinOp,
            ast.UnaryOp,
            ast.Constant,
            ast.Num,
            ast.Add,
            ast.Sub,
            ast.Mult,
            ast.Div,
            ast.FloorDiv,
            ast.Mod,
            ast.Pow,
            ast.UAdd,
            ast.USub,
        )

        for node in ast.walk(tree):
            if not isinstance(node, allowed_node_types):
                raise ValueError("Expression contains disallowed operations")

        # Safely evaluate the expression using a restricted namespace
        result = _safe_eval(tree)

        # Return the result as a string
        if isinstance(result, float):
            # Remove unnecessary decimal places
            if result == int(result):
                return str(int(result))
            else:
                return str(result)
        else:
            return str(result)

    except ValueError:
        raise
    except Exception as e:
        raise ValueError(f"Error processing expression: {str(e)}")


def _safe_eval(node):
    """
    Safely evaluate an AST node containing only mathematical operations.

    Args:
        node: An ast.Expression node to evaluate.

    Returns:
        The result of evaluating the expression.

    Raises:
        ValueError: If the node contains unsupported operations.
    """
    if isinstance(node, ast.Expression):
        return _safe_eval(node.body)

    if isinstance(node, ast.Constant):
        return node.value

    if isinstance(node, ast.Num):  # For Python < 3.8 compatibility
        return node.n

    if isinstance(node, ast.BinOp):
        left = _safe_eval(node.left)
        right = _safe_eval(node.right)

        if isinstance(node.op, ast.Add):
            return left + right
        elif isinstance(node.op, ast.Sub):
            return left - right
        elif isinstance(node.op, ast.Mult):
            return left * right
        elif isinstance(node.op, ast.Div):
            if right == 0:
                raise ValueError("Division by zero")
            return left / right
        elif isinstance(node.op, ast.FloorDiv):
            if right == 0:
                raise ValueError("Division by zero")
            return left // right
        elif isinstance(node.op, ast.Mod):
            if right == 0:
                raise ValueError("Modulo by zero")
            return left % right
        elif isinstance(node.op, ast.Pow):
            return left ** right
        else:
            raise ValueError(f"Unsupported binary operation: {type(node.op)}")

    if isinstance(node, ast.UnaryOp):
        operand = _safe_eval(node.operand)

        if isinstance(node.op, ast.UAdd):
            return +operand
        elif isinstance(node.op, ast.USub):
            return -operand
        else:
            raise ValueError(f"Unsupported unary operation: {type(node.op)}")

    raise ValueError(f"Unsupported node type: {type(node)}")

