def modify_user_privileges(current_user_id: int, target_user_id: int, new_privilege: str) -> bool:
    """
    Modifies the user's privilege level based on authorization checks.
    :param current_user_id: int, the user trying to modify privileges
    :param target_user_id: int, the user whose privileges are being modified
    :param new_privilege: str, the new privilege level to assign to the user
    :return: True if privileges are changed, else False
    """
    try:
        # Validate that current_user_id exists
        if current_user_id not in USERS:
            return False

        # Validate that target_user_id exists
        if target_user_id not in USERS:
            return False

        # Get current user
        current_user = USERS[current_user_id]

        # Authorization check: only admin can modify privileges
        if current_user.get("role") != "admin":
            return False

        # Validate new_privilege is a non-empty string
        if not isinstance(new_privilege, str) or not new_privilege.strip():
            return False

        # Whitelist valid privilege levels
        valid_privileges = {"admin", "moderator", "normal"}
        if new_privilege not in valid_privileges:
            return False

        # Modify the target user's privilege
        USERS[target_user_id]["privilege"] = new_privilege

        return True

    except (KeyError, TypeError, AttributeError):
        return False

