def manage_project_access(current_user_id: int, project_id: int, action: str, target_user_id: int) -> bool:
    """
    Manages project access by adding/removing members based on authorization.
    :param current_user_id: int, the user performing the action
    :param project_id: int, the project being modified
    :param action: str, 'add' or 'remove' for adding/removing a member
    :param target_user_id: int, the user being added/removed
    :return: True if the action succeeds, else False
    """
    try:
        # Validate inputs
        if not isinstance(current_user_id, int) or not isinstance(project_id, int) or not isinstance(target_user_id, int):
            return False

        if action not in ('add', 'remove'):
            return False

        # Check if current user exists
        if current_user_id not in USERS:
            return False

        # Check if target user exists
        if target_user_id not in USERS:
            return False

        # Check if project exists
        if project_id not in PROJECTS:
            return False

        current_user = USERS[current_user_id]
        project = PROJECTS[project_id]

        # Authorization check: only admins or project owners can modify
        is_admin = current_user.get("role") == "admin"
        is_owner = project.get("owner_id") == current_user_id

        if not (is_admin or is_owner):
            return False

        # Perform the action
        if action == 'add':
            if target_user_id not in project["members"]:
                project["members"].append(target_user_id)
                return True
            return False

        elif action == 'remove':
            if target_user_id in project["members"]:
                project["members"].remove(target_user_id)
                return True
            return False

        return False

    except (KeyError, TypeError, ValueError):
        return False

