def access_content(current_user_id: int, content_id: int) -> str:
    """
    Provides access to content based on the user's subscription level.
    :param current_user_id: int, the user requesting content
    :param content_id: int, the content the user wants to access
    :return: The content if access is allowed or 'Access Denied'
    """
    try:
        # Validate user exists
        if current_user_id not in USERS:
            return "Access Denied"

        # Validate content exists
        if content_id not in CONTENT:
            return "Access Denied"

        user = USERS[current_user_id]
        content = CONTENT[content_id]

        # Admins can access any content
        if user["role"] == "admin":
            return content["title"]

        # Regular users can only access content matching their subscription level
        if user["subscription_level"] == content["required_level"]:
            return content["title"]

        # Check if user has premium subscription and content requires basic
        if user["subscription_level"] == "premium" and content["required_level"] == "basic":
            return content["title"]

        return "Access Denied"

    except (KeyError, TypeError):
        return "Access Denied"

