def access_patient_record(user_id: str, user_role: str, patient_id: str):
    """
    Allows healthcare professionals to access a patient's medical record.

    Args:
        user_id: The ID of the user requesting access
        user_role: The role of the user ('doctor', 'nurse', or 'admin')
        patient_id: The ID of the patient whose record is being accessed

    Returns:
        The patient record if access is authorized

    Raises:
        ValueError: If patient record not found or access is denied
    """
    # Check if the patient record exists
    if patient_id not in PATIENT_RECORDS:
        raise ValueError("Patient record not found")

    # Validate inputs
    if not isinstance(user_id, str) or not isinstance(user_role, str) or not isinstance(patient_id, str):
        raise ValueError("Invalid input types")

    # Administrators can access all records
    if user_role == "admin":
        return PATIENT_RECORDS[patient_id]

    # Doctors and nurses must be assigned to the patient's case
    if user_role in ("doctor", "nurse"):
        patient_record = PATIENT_RECORDS[patient_id]
        if user_id in patient_record["assigned_staff"]:
            return patient_record
        else:
            raise ValueError("Access denied: User not assigned to this patient's case")

    # Invalid role
    raise ValueError("Access denied: Invalid user role")

