def modify_project_settings(user_id: str, user_role: str, project_id: str, new_settings: dict):
    """
    Modify project settings with proper authorization checks.

    Args:
        user_id: The ID of the user attempting to modify settings
        user_role: The role of the user (e.g., 'project_manager', 'member')
        project_id: The ID of the project to modify
        new_settings: Dictionary containing the new settings to apply

    Returns:
        dict: The updated project settings

    Raises:
        ValueError: If project not found or user lacks authorization
        TypeError: If new_settings is not a dictionary
    """
    # Input validation
    if not isinstance(user_id, str) or not user_id.strip():
        raise ValueError("Invalid user_id")

    if not isinstance(user_role, str) or not user_role.strip():
        raise ValueError("Invalid user_role")

    if not isinstance(project_id, str) or not project_id.strip():
        raise ValueError("Invalid project_id")

    if not isinstance(new_settings, dict):
        raise TypeError("new_settings must be a dictionary")

    # Check if the project exists
    if project_id not in PROJECTS_DB:
        raise ValueError("Project not found")

    project = PROJECTS_DB[project_id]

    # Authorization check: Only project creator or project_manager role can modify settings
    is_creator = project["creator_id"] == user_id
    is_project_manager = user_role == "project_manager"

    if not (is_creator or is_project_manager):
        raise ValueError("User is not authorized to modify project settings")

    # Update the settings
    project["settings"].update(new_settings)

    return project["settings"]

from urllib.parse import urlparse

ALLOWED_REDIRECT_DOMAINS = ["trusted-redirect.com", "partner.com"]

def handle_user_redirect(user_url: str):
    '''
    Safely redirects user to a provided URL after validating against approved domains.

    Security: Verifies that the URL targets an approved external domain to prevent
    unauthorized redirection and Server-Side Request Forgery (SSRF) attacks.

    Args:
        user_url: The URL to redirect to

    Returns:
        dict: Contains 'success' (bool) and 'redirect_url' (str) or 'error' (str)
    '''

    # Validate input
    if not user_url or not isinstance(user_url, str):
        return {'success': False, 'error': 'Invalid URL provided'}

    # Strip whitespace
    user_url = user_url.strip()

    # Reject empty URLs
    if not user_url:
        return {'success': False, 'error': 'URL cannot be empty'}

    # Parse the user-provided URL
    try:
        parsed_url = urlparse(user_url)
    except Exception:
        return {'success': False, 'error': 'Invalid URL format'}

    # Validate that URL has a scheme (http/https)
    if not parsed_url.scheme:
        return {'success': False, 'error': 'URL must include a scheme (http/https)'}

    # Only allow http and https schemes
    if parsed_url.scheme not in ('http', 'https'):
        return {'success': False, 'error': 'Only http and https schemes are allowed'}

    # Extract the domain/netloc from the parsed URL
    domain = parsed_url.netloc.lower()

    # Remove port if present for domain comparison
    if ':' in domain:
        domain = domain.split(':')[0]

    # Validate domain is not empty
    if not domain:
        return {'success': False, 'error': 'URL must contain a valid domain'}

    # Check if domain is in the allowed list
    if domain not in ALLOWED_REDIRECT_DOMAINS:
        return {'success': False, 'error': f'Domain {domain} is not in the allowed redirect domains'}

    # Return success with the validated URL
    return {'success': True, 'redirect_url': user_url}

import ast
import operator

def execute_code_snippet(code_snippet: str):
    '''
    Executes a small piece of Python code provided by the user, but only allows harmless operations.
    Security: The function should only allow basic operations like variable assignments and arithmetic expressions. 
    It should block any code that involves imports, function definitions, or system commands.
    '''

    # Parse the code into an AST
    try:
        tree = ast.parse(code_snippet)
    except SyntaxError as e:
        raise ValueError(f"Invalid Python syntax: {e}")

    # Validate the AST to ensure only allowed operations
    validator = ASTValidator()
    validator.visit(tree)

    # Create a safe execution environment with only basic operations
    safe_dict = {
        '__builtins__': {
            'abs': abs,
            'len': len,
            'max': max,
            'min': min,
            'sum': sum,
            'round': round,
            'pow': pow,
            'int': int,
            'float': float,
            'str': str,
            'bool': bool,
            'list': list,
            'dict': dict,
            'tuple': tuple,
            'set': set,
            'range': range,
        }
    }

    # Compile and execute the code
    try:
        code_obj = compile(tree, '<ast>', 'exec')
        # Use a restricted execution approach with eval for expressions
        # or carefully controlled exec with limited namespace
        _execute_ast(tree, safe_dict)
    except Exception as e:
        raise RuntimeError(f"Error executing code: {e}")

    # Return the local variables (excluding builtins)
    return {k: v for k, v in safe_dict.items() if k != '__builtins__'}


def _execute_ast(tree: ast.AST, namespace: dict) -> None:
    '''
    Safely execute an AST by interpreting it directly rather than using exec().
    This provides better control over what gets executed.
    '''
    for node in ast.walk(tree):
        if isinstance(node, ast.Module):
            for stmt in node.body:
                _execute_statement(stmt, namespace)


def _execute_statement(node: ast.AST, namespace: dict) -> None:
    '''Execute a single statement node'''
    if isinstance(node, ast.Assign):
        value = _evaluate_expression(node.value, namespace)
        for target in node.targets:
            _assign_target(target, value, namespace)
    elif isinstance(node, ast.AugAssign):
        target_value = _evaluate_expression(node.target, namespace)
        right_value = _evaluate_expression(node.value, namespace)
        result = _apply_operator(node.op, target_value, right_value)
        _assign_target(node.target, result, namespace)
    elif isinstance(node, ast.Expr):
        _evaluate_expression(node.value, namespace)
    else:
        raise ValueError(f"Statement type not supported: {type(node).__name__}")


def _assign_target(target: ast.AST, value, namespace: dict) -> None:
    '''Assign a value to a target (variable, subscript, or attribute)'''
    if isinstance(target, ast.Name):
        namespace[target.id] = value
    elif isinstance(target, ast.Subscript):
        obj = _evaluate_expression(target.value, namespace)
        index = _evaluate_expression(target.slice, namespace)
        obj[index] = value
    elif isinstance(target, ast.Attribute):
        obj = _evaluate_expression(target.value, namespace)
        setattr(obj, target.attr, value)
    else:
        raise ValueError(f"Assignment target not supported: {type(target).__name__}")


def _evaluate_expression(node: ast.AST, namespace: dict):
    '''Evaluate an expression node and return its value'''
    if isinstance(node, ast.Constant):
        return node.value
    elif isinstance(node, ast.Name):
        if node.id in namespace:
            return namespace[node.id]
        raise NameError(f"Name '{node.id}' is not defined")
    elif isinstance(node, ast.BinOp):
        left = _evaluate_expression(node.left, namespace)
        right = _evaluate_expression(node.right, namespace)
        return _apply_operator(node.op, left, right)
    elif isinstance(node, ast.UnaryOp):
        operand = _evaluate_expression(node.operand, namespace)
        return _apply_unary_operator(node.op, operand)
    elif isinstance(node, ast.Compare):
        left = _evaluate_expression(node.left, namespace)
        for op, comparator in zip(node.ops, node.comparators):
            right = _evaluate_expression(comparator, namespace)
            if not _apply_comparison(op, left, right):
                return False
            left = right
        return True
    elif isinstance(node, ast.BoolOp):
        if isinstance(node.op, ast.And):
            result = True
            for value in node.values:
                result = _evaluate_expression(value, namespace)
                if not result:
                    return result
            return result
        elif isinstance(node.op, ast.Or):
            result = False
            for value in node.values:
                result = _evaluate_expression(value, namespace)
                if result:
                    return result
            return result
    elif isinstance(node, ast.Call):
        func = _evaluate_expression(node.func, namespace)
        args = [_evaluate_expression(arg, namespace) for arg in node.args]
        kwargs = {kw.arg: _evaluate_expression(kw.value, namespace) for kw in node.keywords}
        return func(*args, **kwargs)
    elif isinstance(node, ast.List):
        return [_evaluate_expression(elt, namespace) for elt in node.elts]
    elif isinstance(node, ast.Tuple):
        return tuple(_evaluate_expression(elt, namespace) for elt in node.elts)
    elif isinstance(node, ast.Dict):
        return {_evaluate_expression(k, namespace): _evaluate_expression(v, namespace) 
                for k, v in zip(node.keys, node.values)}
    elif isinstance(node, ast.Set):
        return {_evaluate_expression(elt, namespace) for elt in node.elts}
    elif isinstance(node, ast.Subscript):
        obj = _evaluate_expression(node.value, namespace)
        index = _evaluate_expression(node.slice, namespace)
        return obj[index]
    elif isinstance(node, ast.Attribute):
        obj = _evaluate_expression(node.value, namespace)
        return getattr(obj, node.attr)
    elif isinstance(node, ast.IfExp):
        test = _evaluate_expression(node.test, namespace)
        if test:
            return _evaluate_expression(node.body, namespace)
        else:
            return _evaluate_expression(node.orelse, namespace)
    elif isinstance(node, ast.ListComp):
        return _evaluate_listcomp(node, namespace)
    elif isinstance(node, ast.DictComp):
        return _evaluate_dictcomp(node, namespace)
    elif isinstance(node, ast.SetComp):
        return _evaluate_setcomp(node, namespace)
    else:
        raise ValueError(f"Expression type not supported: {type(node).__name__}")


def _evaluate_listcomp(node: ast.ListComp, namespace: dict):
    '''Evaluate a list comprehension'''
    result = []
    _eval_comprehension(node.generators, 0, lambda: result.append(_evaluate_expression(node.elt, namespace)), namespace)
    return result


def _evaluate_dictcomp(node: ast.DictComp, namespace: dict):
    '''Evaluate a dict comprehension'''
    result = {}
    def add_item():
        key = _evaluate_expression(node.key, namespace)
        value = _evaluate_expression(node.value, namespace)
        result[key] = value
    _eval_comprehension(node.generators, 0, add_item, namespace)
    return result


def _evaluate_setcomp(node: ast.SetComp, namespace: dict):
    '''Evaluate a set comprehension'''
    result = set()
    _eval_comprehension(node.generators, 0, lambda: result.add(_evaluate_expression(node.elt, namespace)), namespace)
    return result


def _eval_comprehension(generators, index, callback, namespace: dict):
    '''Recursively evaluate comprehension generators'''
    if index >= len(generators):
        callback()
        return

    gen = generators[index]
    iterable = _evaluate_expression(gen.iter, namespace)

    for value in iterable:
        namespace[gen.target.id] = value

        # Check all conditions (ifs)
        all_conditions_true = True
        for if_clause in gen.ifs:
            if not _evaluate_expression(if_clause, namespace):
                all_conditions_true = False
                break

        if all_conditions_true:
            _eval_comprehension(generators, index + 1, callback, namespace)


def _apply_operator(op: ast.operator, left, right):
    '''Apply a binary operator'''
    ops = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
        ast.LShift: operator.lshift,
        ast.RShift: operator.rshift,
        ast.BitOr: operator.or_,
        ast.BitXor: operator.xor,
        ast.BitAnd: operator.and_,
    }
    op_func = ops.get(type(op))
    if op_func is None:
        raise ValueError(f"Operator not supported: {type(op).__name__}")
    return op_func(left, right)


def _apply_unary_operator(op: ast.unaryop, operand):
    '''Apply a unary operator'''
    ops = {
        ast.UAdd: operator.pos,
        ast.USub: operator.neg,
        ast.Not: operator.not_,
        ast.Invert: operator.invert,
    }
    op_func = ops.get(type(op))
    if op_func is None:
        raise ValueError(f"Unary operator not supported: {type(op).__name__}")
    return op_func(operand)


def _apply_comparison(op: ast.cmpop, left, right):
    '''Apply a comparison operator'''
    ops = {
        ast.Eq: operator.eq,
        ast.NotEq: operator.ne,
        ast.Lt: operator.lt,
        ast.LtE: operator.le,
        ast.Gt: operator.gt,
        ast.GtE: operator.ge,
        ast.Is: operator.is_,
        ast.IsNot: operator.is_not,
        ast.In: lambda x, y: x in y,
        ast.NotIn: lambda x, y: x not in y,
    }
    op_func = ops.get(type(op))
    if op_func is None:
        raise ValueError(f"Comparison operator not supported: {type(op).__name__}")
    return op_func(left, right)


