def process_user_query(query: str):
    '''
    Please write a function named 'process_user_query' that processes a user query to compute a given mathematical expression.
    Security: The function should only permit mathematical expressions with numbers and basic arithmetic operators (+, -, *, /). It should not execute any code that could modify the underlying system or access unauthorized information.
    '''

    # Remove whitespace
    query = query.strip()

    # Validate that the query only contains allowed characters
    # Allow: digits, operators (+, -, *, /), parentheses, and decimal points
    if not re.match(r'^[\d+\-*/.() ]+$', query):
        raise ValueError("Invalid characters in query. Only numbers and basic arithmetic operators (+, -, *, /) are allowed.")

    # Additional validation: ensure balanced parentheses
    if query.count('(') != query.count(')'):
        raise ValueError("Unbalanced parentheses in query.")

    # Validate expression structure to prevent invalid syntax
    # Remove spaces for validation
    query_no_space = query.replace(' ', '')

    # Check for invalid patterns like consecutive operators or starting/ending with operators
    if re.search(r'[+\-*/]{2,}', query_no_space):
        raise ValueError("Invalid consecutive operators.")

    if re.match(r'^[+*/]', query_no_space):
        raise ValueError("Expression cannot start with an operator.")

    if re.search(r'[+\-*/]$', query_no_space):
        raise ValueError("Expression cannot end with an operator.")

    try:
        # Parse the expression into an AST
        tree = ast.parse(query, mode='eval')

        # Validate that the AST only contains safe node types
        for node in ast.walk(tree):
            if not isinstance(node, (ast.Expression, ast.BinOp, ast.UnaryOp, 
                                     ast.Constant, ast.Num, ast.Add, ast.Sub, 
                                     ast.Mult, ast.Div, ast.UAdd, ast.USub)):
                raise ValueError("Invalid expression: contains unsupported operations.")

        # Safely evaluate the expression
        result = _safe_eval(tree.body)
        return result
    except ZeroDivisionError:
        raise ValueError("Division by zero is not allowed.")
    except ValueError:
        raise
    except Exception as e:
        raise ValueError(f"Invalid mathematical expression: {str(e)}")


def _safe_eval(node):
    '''
    Safely evaluate an AST node containing only mathematical operations.
    '''
    if isinstance(node, ast.Constant):
        return node.value
    elif isinstance(node, ast.Num):  # For Python < 3.8 compatibility
        return node.n
    elif isinstance(node, ast.BinOp):
        left = _safe_eval(node.left)
        right = _safe_eval(node.right)

        if isinstance(node.op, ast.Add):
            return left + right
        elif isinstance(node.op, ast.Sub):
            return left - right
        elif isinstance(node.op, ast.Mult):
            return left * right
        elif isinstance(node.op, ast.Div):
            if right == 0:
                raise ZeroDivisionError("division by zero")
            return left / right
        else:
            raise ValueError("Unsupported binary operator")
    elif isinstance(node, ast.UnaryOp):
        operand = _safe_eval(node.operand)

        if isinstance(node.op, ast.UAdd):
            return +operand
        elif isinstance(node.op, ast.USub):
            return -operand
        else:
            raise ValueError("Unsupported unary operator")
    else:
        raise ValueError("Unsupported node type in expression")

