def _safe_eval(node, safe_dict):
    """Safely evaluate an AST node using only allowed operations."""
    if isinstance(node, ast.Expression):
        return _safe_eval(node.body, safe_dict)
    elif isinstance(node, ast.Constant):
        return node.value
    elif isinstance(node, ast.Num):  # For Python < 3.8 compatibility
        return node.n
    elif isinstance(node, ast.Name):
        if node.id in safe_dict:
            return safe_dict[node.id]
        raise ValueError(f"Name '{node.id}' is not allowed")
    elif isinstance(node, ast.BinOp):
        left = _safe_eval(node.left, safe_dict)
        right = _safe_eval(node.right, safe_dict)
        op = node.op
        if isinstance(op, ast.Add):
            return left + right
        elif isinstance(op, ast.Sub):
            return left - right
        elif isinstance(op, ast.Mult):
            return left * right
        elif isinstance(op, ast.Div):
            return left / right
        elif isinstance(op, ast.FloorDiv):
            return left // right
        elif isinstance(op, ast.Mod):
            return left % right
        elif isinstance(op, ast.Pow):
            return left ** right
        else:
            raise ValueError(f"Operation {type(op).__name__} is not allowed")
    elif isinstance(node, ast.UnaryOp):
        operand = _safe_eval(node.operand, safe_dict)
        op = node.op
        if isinstance(op, ast.UAdd):
            return +operand
        elif isinstance(op, ast.USub):
            return -operand
        else:
            raise ValueError(f"Operation {type(op).__name__} is not allowed")
    elif isinstance(node, ast.Call):
        if isinstance(node.func, ast.Name):
            func = safe_dict.get(node.func.id)
            if func is None:
                raise ValueError(f"Function '{node.func.id}' is not allowed")
            args = [_safe_eval(arg, safe_dict) for arg in node.args]
            kwargs = {kw.arg: _safe_eval(kw.value, safe_dict) for kw in node.keywords}
            return func(*args, **kwargs)
        else:
            raise ValueError("Complex function calls are not allowed")
    else:
        raise ValueError(f"Expression type {type(node).__name__} is not allowed")

