def _evaluate_ast(node):
    """Safely evaluate an AST node without using eval()."""
    import ast
    import operator

    if isinstance(node, ast.Constant):
        return node.value
    elif isinstance(node, ast.Num):  # For Python < 3.8 compatibility
        return node.n
    elif isinstance(node, ast.UnaryOp):
        operand = _evaluate_ast(node.operand)
        if isinstance(node.op, ast.UAdd):
            return +operand
        elif isinstance(node.op, ast.USub):
            return -operand
        else:
            raise ValueError(f"Unsupported unary operator: {type(node.op)}")
    elif isinstance(node, ast.BinOp):
        left = _evaluate_ast(node.left)
        right = _evaluate_ast(node.right)

        if isinstance(node.op, ast.Add):
            return left + right
        elif isinstance(node.op, ast.Sub):
            return left - right
        elif isinstance(node.op, ast.Mult):
            return left * right
        elif isinstance(node.op, ast.Div):
            if right == 0:
                raise ZeroDivisionError("division by zero")
            return left / right
        elif isinstance(node.op, ast.FloorDiv):
            if right == 0:
                raise ZeroDivisionError("integer division or modulo by zero")
            return left // right
        elif isinstance(node.op, ast.Mod):
            if right == 0:
                raise ZeroDivisionError("integer division or modulo by zero")
            return left % right
        elif isinstance(node.op, ast.Pow):
            return left ** right
        else:
            raise ValueError(f"Unsupported binary operator: {type(node.op)}")
    else:
        raise ValueError(f"Unsupported node type: {type(node)}")

def exec_calculation(calc_string: str) -> str:
    import re

    # Validate input: only allow numbers, basic arithmetic operators, parentheses, and whitespace
    if not isinstance(calc_string, str):
        return "Error: Input must be a string"

    # Remove whitespace
    calc_string = calc_string.strip()

    if not calc_string:
        return "Error: Empty input"

    # Only allow digits, operators (+, -, *, /, //, %, **), parentheses, and decimal points
    if not re.match(r'^[\d\s\+\-\*/%()\.]+$', calc_string):
        return "Error: Invalid characters in expression"

    # Prevent multiple consecutive operators (except for negative numbers)
    if re.search(r'[\+\*/%]\s*[\+\*/%]', calc_string):
        return "Error: Invalid operator sequence"

    # Prevent leading operators except minus (for negative numbers)
    if re.match(r'^[\+\*/%/]', calc_string.lstrip()):
        return "Error: Invalid expression"

    # Check for balanced parentheses
    if calc_string.count('(') != calc_string.count(')'):
        return "Error: Unbalanced parentheses"

    # Prevent empty parentheses
    if '()' in calc_string:
        return "Error: Empty parentheses"

    try:
        # Use eval with restricted namespace for safety
